INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$1,000+ prebuilt connectors$q$, $q$Connects to databases, cloud apps, spreadsheets, APIs, and streaming sources without custom integration work.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Magic ETL$q$, $q$A visual, drag-and-drop data transformation canvas that lets non-engineers clean and reshape data before it hits dashboards.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Cloud data warehouse$q$, $q$Domo's Adrenaline engine stores and indexes ingested data so dashboards refresh quickly even at large scale.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Domo Everywhere$q$, $q$Embedding and white-labeling framework for surfacing live dashboards inside customer-facing products or partner portals.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$App Studio$q$, $q$Low-code tooling for building interactive, workflow-style data apps on top of governed datasets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Domo.AI$q$, $q$Generative AI features for natural-language querying, dashboard summarization, and automated data storytelling.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Mobile-first dashboards$q$, $q$Dashboards are designed to be fully usable on phones and tablets, not just desktop browsers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Personalized Data Permissions (PDP)$q$, $q$Row-level governance controls so different users or embedded audiences see only the data relevant to them.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$All-in-one platform combines connectors, ETL, warehousing, visualization, and embedding without needing separate tools.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Mobile-first dashboards make Domo unusually strong for executives who need metrics on the go.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Domo Everywhere makes embedding live analytics into customer-facing products straightforward.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Unlimited users and full feature access are included even on paid consumption contracts, avoiding per-seat gatekeeping of features.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Consumption-based credit pricing is opaque and makes total cost of ownership difficult to forecast in advance.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$No published price list; every deployment requires a sales conversation and custom quote.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Effective cost per user can be significantly higher than competitors like Power BI, especially at smaller team sizes.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Heavy platform breadth can mean a steeper learning curve than narrower, single-purpose visualization tools.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Is Domo free to use?$q$, $q$Domo is not permanently free, but it offers a 30-day full-access trial with unlimited users and no credit card required. Ongoing use requires a paid, custom-quoted contract.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$How does Domo pricing work?$q$, $q$Domo uses a consumption-based credit model. Customers commit to a pool of credits through an annual or multi-year contract, and credits are consumed based on platform usage such as data processing and refreshes, rather than a fixed price per named user.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Who founded Domo?$q$, $q$Domo was founded in 2010 by Josh James, who previously co-founded and sold the web-analytics company Omniture to Adobe.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Is Domo a public company?$q$, $q$Yes. Domo, Inc. has traded on the NASDAQ under the ticker DOMO since its June 2018 initial public offering.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$What are the main alternatives to Domo?$q$, $q$Common alternatives include Tableau, Microsoft Power BI, Google Looker, and Qlik Sense, along with embedded-analytics specialists such as Sisense.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Can Domo be embedded into another product?$q$, $q$Yes. Domo Everywhere is a dedicated embedding and white-labeling framework that lets companies surface live Domo dashboards inside their own customer-facing applications.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Executive and operational reporting$q$, $q$Centralizing sales, marketing, operations, and finance metrics into mobile-friendly dashboards that leadership can check from any device.$q$, $q$Enterprise and mid-market executives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Embedded customer-facing analytics$q$, $q$Using Domo Everywhere to white-label and embed live dashboards inside a company's own SaaS product or partner portal.$q$, $q$Product and ISV teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Multi-location operational monitoring$q$, $q$Retail chains, healthcare networks, and franchise businesses tracking near-real-time performance across many locations from one platform.$q$, $q$Retail, healthcare, and franchise operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Free Trial$q$, $q$Free$q$, $q$30-day trial$q$, NULL, $q$["Unlimited users","Full platform access","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$Standard / Enterprise (Custom)$q$, $q$Custom (credit-based, quote required)$q$, $q$Annual or multi-year contract$q$, NULL, $q$["Privileged, Participant, and Social user licensing tiers","1,000+ data connectors","Magic ETL and cloud data warehouse","Domo.AI generative analytics","Domo Everywhere embedding","Dedicated account support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Domo is a cloud-native business intelligence platform that unifies data integration, a managed data warehouse, dashboarding, low-code app building, and AI-assisted analytics in a single product. It was built to let executives and operational teams see up-to-date metrics on any device, not just data analysts working in a desktop BI tool.$q$, $q$Founded in 2010 by Josh James (previously the co-founder of Omniture) and headquartered in American Fork, Utah, Domo has been publicly traded on the NASDAQ under the ticker DOMO since its 2018 IPO. The company positions itself as an all-in-one alternative to stitching together separate ETL, warehouse, and visualization tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Domo ships with more than 1,000 pre-built data connectors covering databases, cloud applications, spreadsheets, and APIs, along with Magic ETL, a visual drag-and-drop data transformation canvas that does not require SQL knowledge.$q$, $q$Domo Everywhere lets organizations embed live, white-labeled dashboards into customer-facing products or portals, while App Studio provides low-code tools for building interactive data apps on top of governed datasets. Domo.AI adds natural-language querying and automated narrative summaries on top of dashboards.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Since 2023, Domo has priced the platform using a consumption-based credit model rather than fixed per-user tiers: customers commit to an annual or multi-year contract for a pool of credits that is drawn down by data-related usage, with all users and core features included from day one.$q$, $q$Domo does not publish list prices; every paid deployment is custom-quoted, and independent analyses of customer contracts put the realistic entry point at roughly $30,000 per year. A free 30-day full-featured trial with unlimited users is available without a credit card.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e2f3e916-a6c5-4d8f-9d3a-df43e916f33c', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$150+ supported devices and protocols$q$, $q$Native support for Z-Wave, Zigbee, MQTT, Philips Hue, RFXCOM, and many other hardware integrations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Lightweight C++ core$q$, $q$Uses under 50MB of RAM, letting it run on constrained hardware like a Raspberry Pi Zero.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Local-first, no cloud required$q$, $q$All data and automations run on the user's own hardware with no mandatory cloud account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$dzVents scripting engine$q$, $q$A Lua-based scripting system for writing concise, readable automation event scripts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Blockly visual automation$q$, $q$A drag-and-drop visual scripting option for users who prefer not to write code.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$JSON API$q$, $q$Exposes system state and controls programmatically for third-party dashboards and integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Official Android app$q$, $q$Native mobile client for monitoring and controlling a Domoticz installation on the go.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Responsive HTML5 web interface$q$, $q$Built-in dashboard that automatically adapts to desktop and mobile browsers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Completely free and open source with no subscriptions or paywalled features.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Extremely light on system resources compared to alternatives like Home Assistant.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Strong support for legacy protocols such as 433MHz RF and RFXCOM hardware.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Runs entirely locally, avoiding cloud dependency and vendor lock-in.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Smaller community and integration library than the market-leading Home Assistant.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$User interface feels dated compared to more modern smart home dashboards.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Slower release cadence, so support for brand-new devices can lag behind competitors.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Requires more technical comfort to set up and maintain than consumer smart home hubs.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Is Domoticz free?$q$, $q$Yes. Domoticz is fully free and open source, with no subscriptions, license fees, or paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$What platforms does Domoticz run on?$q$, $q$Domoticz runs on Linux, Windows, and Raspberry Pi, and it can operate on hardware as small as a Raspberry Pi Zero thanks to its lightweight C++ codebase.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Does Domoticz require an internet connection?$q$, $q$No. Domoticz runs and automates entirely on local hardware; an internet connection is only needed for optional integrations with external cloud services.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$How is Domoticz different from Home Assistant?$q$, $q$Domoticz is significantly lighter on system resources and has strong legacy protocol support, while Home Assistant has a much larger integration library, community, and faster release cadence.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Can I automate Domoticz without writing code?$q$, $q$Yes. Domoticz includes a visual Blockly editor for building automations without code, in addition to Lua-based dzVents and Python scripting for more advanced use cases.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Is there a mobile app for Domoticz?$q$, $q$Yes, Domoticz has an official Android client application, and its web interface is also mobile-responsive for use in any modern browser.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$DIY smart home automation$q$, $q$Hobbyists building custom home automation setups on Raspberry Pi or repurposed hardware without paying ongoing subscription fees.$q$, $q$DIY hobbyists and makers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Privacy-focused local control$q$, $q$Users who want full local control over their smart home data without relying on a vendor's cloud infrastructure.$q$, $q$Privacy-conscious homeowners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Legacy and resource-constrained deployments$q$, $q$Running home automation on older 433MHz RF hardware or extremely low-power devices where heavier platforms are impractical.$q$, $q$Technical users with legacy hardware$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code and software","Official Android app","150+ device integrations","Community forum and wiki support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Domoticz is a free, open-source home automation system that runs entirely on hardware the user controls, with no cloud account or subscription required. It monitors and controls devices such as lights, switches, thermostats, and a wide range of sensors, and supports more than 150 hardware protocols including Z-Wave, Zigbee, MQTT, and Philips Hue.$q$, $q$Originally released in 2012 by a Dutch developer to support the Netherlands' P1 Smart Meter and RFXCOM RF hardware, Domoticz has grown into a community-maintained open-source project with contributors on GitHub and crowdsourced translations into languages beyond English.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Written in C++, Domoticz is notably lightweight, reportedly using under 50MB of RAM, which lets it run on hardware as small as a Raspberry Pi Zero as well as full Linux or Windows servers.$q$, $q$Automation can be scripted through the Lua-based dzVents engine, a visual Blockly editor, or Python, and the platform exposes a JSON API for third-party dashboards and integrations. An official Android app and a responsive HTML5 web interface cover mobile and desktop access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Domoticz is entirely free and open source with no paid tiers, subscriptions, or feature paywalls. The only costs involved are for the hardware it runs on and any smart home devices or radio transceivers a user chooses to integrate.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('079c889d-8df9-4612-92ff-bb745bc64902', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Group meeting polls$q$, $q$Organizers propose multiple date and time options and invitees vote, making it easy to find a time that works for large groups.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Doodle 1:1$q$, $q$Quick one-on-one meeting booking that lets an organizer share their real-time availability with a single invitee.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Booking Page$q$, $q$A public, always-available scheduling page where others can book open time directly on the organizer's calendar.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Calendar sync$q$, $q$Two-way integration with Google Calendar, Outlook, Office 365, and iCal to reflect real, up-to-date availability.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Video conferencing integration$q$, $q$Automatically attaches meeting links from Google Meet, Zoom, Microsoft Teams, or Webex to confirmed bookings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Stripe payment collection$q$, $q$Lets consultants and service providers charge for booked time directly through their booking page.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Team scheduling$q$, $q$Shared booking pages and team availability views for coordinating meetings across multiple team members.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Zapier integration$q$, $q$Connects Doodle to thousands of other apps for workflows not covered by native integrations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Group polling remains best-in-class for coordinating meetings across many participants and time zones.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Native integrations with major video conferencing tools attach meeting links automatically.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Free plan is genuinely usable for basic polling and single-page booking needs.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Long track record and strong brand recognition, especially across Europe.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Relies on Zapier rather than a broad native integration marketplace for many third-party tools.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Booking links are not single-use, so anyone with the link can book time, unlike some competitors.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Team plan caps out at five users before requiring a custom Enterprise conversation.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Less focused than Calendly on advanced link-based booking workflows and analytics.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Is Doodle free to use?$q$, $q$Yes. Doodle offers a free plan with basic polling and booking page functionality. Paid Pro and Team plans unlock unlimited polls, more booking pages, and team features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$How much does Doodle cost?$q$, $q$Doodle's Pro plan costs $6.95 per user per month billed annually, and the Team plan (up to five users) costs $8.95 per user per month billed annually. Enterprise pricing is custom-quoted.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Who founded Doodle?$q$, $q$Doodle was founded in 2007 by ETH Zurich students Michael Naf and Paul Sevinc, and it is now fully owned by the Swiss media company TX Group.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$What is Doodle used for?$q$, $q$Doodle is used to coordinate meeting times across groups through polls, book one-on-one meetings, and let others book open time on a calendar through a public booking page.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$How is Doodle different from Calendly?$q$, $q$Doodle is best known for its group-polling functionality for coordinating many participants, while Calendly focuses primarily on fast, single-use, link-based individual bookings with a larger native integration ecosystem.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Does Doodle integrate with video conferencing tools?$q$, $q$Yes. Doodle natively integrates with Google Meet, Zoom, Microsoft Teams, and Webex, automatically attaching a meeting link once a time is confirmed.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Group meeting coordination$q$, $q$Finding a date and time that works across many participants, such as interview panels or board meetings, using group polls.$q$, $q$Recruiters, HR teams, and executives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Client and prospect booking$q$, $q$Sharing a public booking page so clients, prospects, or students can book available time without back-and-forth emails.$q$, $q$Sales reps, consultants, and educators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Team scheduling$q$, $q$Coordinating shared availability and bookings across a small team using collaborative booking pages.$q$, $q$Small teams and customer success groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Basic meeting polls","One booking page","Calendar sync"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Pro$q$, $q$$6.95/user/month$q$, $q$Billed annually$q$, NULL, $q$["Unlimited polls and booking pages","Video conferencing integration","Stripe payment collection","Removal of Doodle branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Team$q$, $q$$8.95/user/month$q$, $q$Billed annually (up to 5 users)$q$, NULL, $q$["Everything in Pro","Shared team booking pages","Team availability views","Centralized billing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Single sign-on (SSO)","Advanced admin controls","Dedicated support","Custom user limits"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Doodle is a scheduling platform built around meeting polls, where an organizer proposes several time options and invitees vote on which ones work, alongside modern one-on-one and public booking page tools similar to Calendly.$q$, $q$Founded in 2007 by ETH Zurich students Michael Naf and Paul Sevinc, Doodle is headquartered in Zurich, Switzerland and has been fully owned by Swiss media company TX Group since 2022, operating with offices in Zurich, Berlin, Belgrade, Atlanta, and New York.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Doodle syncs with Google Calendar, Outlook, Office 365, and iCal so availability reflects a user's real schedule, and it natively attaches video links from Google Meet, Zoom, Microsoft Teams, or Webex to confirmed meetings.$q$, $q$Beyond its original group polls, Doodle now offers Doodle 1:1 for quick individual meetings and Booking Page for Calendly-style public scheduling, plus Stripe payment collection for paid bookings.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Doodle offers a free plan with basic polling and booking functionality, a Pro plan at $6.95 per user per month (billed annually) for individuals, and a Team plan at $8.95 per user per month (billed annually) for up to five collaborators, with a custom-quoted Enterprise tier for larger organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f952f07d-b3f7-4527-af58-4d07608f83cf', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Centralized secrets store$q$, $q$Single source of truth for API keys, credentials, and environment variables across every project and environment.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Config inheritance$q$, $q$Environment-scoped configs (development, staging, production) can inherit shared values to avoid duplication.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$CLI and SDKs$q$, $q$Fetches secrets programmatically into applications, CI pipelines, and infrastructure without manual copy-paste.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Automatic secret rotation$q$, $q$Rotates credentials on a schedule or trigger and propagates the update to every consuming service.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Change requests and approvals$q$, $q$Requires review and approval before sensitive secret changes go live, reducing accidental misconfiguration.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$SAML SSO and RBAC$q$, $q$Enterprise-grade access control with single sign-on and granular role-based permissions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Native integrations$q$, $q$Connects directly to Kubernetes, Docker, Vercel, AWS, GitHub Actions, and Terraform, among others.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Activity logging$q$, $q$Tracks who accessed or changed which secrets and when, for audit and compliance purposes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Transparent, publicly listed pricing rather than opaque quote-based plans common among security tools.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Free tier for up to three users makes it accessible for small teams and side projects.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Strong developer experience with a well-regarded CLI and broad native integrations.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Does not charge extra for AI agents or other non-human identities accessing secrets.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Full dynamic secrets generation is newer and less mature than HashiCorp Vault's implementation.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Team plan at $21/user/month can add up quickly for larger engineering organizations.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Primarily a managed SaaS product, so teams needing full self-hosted control must go through the custom Enterprise tier.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Fewer very deep enterprise compliance certifications than some longer-established competitors.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Is Doppler free?$q$, $q$Yes, Doppler's Developer plan is free for up to three users, with additional users billed at $8/month each. Paid Team and Enterprise plans unlock collaboration and security features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$How much does Doppler's Team plan cost?$q$, $q$The Team plan costs $21 per user per month and includes a 14-day free trial, plus features like SAML SSO, change requests, and automatic secret rotation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Who founded Doppler?$q$, $q$Doppler was founded in 2018 by Brian Vallelunga, Jack Legg, and Cesar D'Onofrio, and went through Y Combinator.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$How is Doppler different from HashiCorp Vault?$q$, $q$Doppler is a managed, developer-friendly SaaS product optimized for fast setup and ease of use, while HashiCorp Vault is a highly configurable, self-hostable platform with deeper dynamic-secrets capabilities aimed at large enterprises with dedicated platform engineering teams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Does Doppler charge extra for AI agents accessing secrets?$q$, $q$No. Doppler's pricing is per human seat; AI agents and other non-human identities can access secrets under the same governance model without additional per-seat fees.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Can Doppler be self-hosted?$q$, $q$Doppler is primarily offered as managed SaaS, but the custom-priced Enterprise plan includes an on-premise or private cloud deployment option.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Multi-environment secret syncing$q$, $q$Keeping API keys and credentials consistent and automatically propagated across development, staging, and production environments.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$CI/CD and infrastructure automation$q$, $q$Injecting secrets securely into GitHub Actions, Kubernetes, and Terraform workflows without hardcoding them in configuration files.$q$, $q$DevOps and platform engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Compliance-driven access control$q$, $q$Enforcing SAML SSO, role-based permissions, and audit logging for secrets access to satisfy security and compliance requirements.$q$, $q$Security and compliance teams at scaling companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Developer$q$, $q$Free for 3 users, then $8/user/month$q$, $q$Monthly$q$, NULL, $q$["Doppler CLI","Service tokens","Email alerts","3-day activity logs","API and webhook access","5 config syncs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Team$q$, $q$$21/user/month$q$, $q$Monthly (14-day free trial)$q$, NULL, $q$["Change requests","SAML SSO","Role-based access control","90-day activity logs","Automatic secret rotation","Service accounts","100 config syncs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["On-premise or cloud deployment","Enterprise SCIM","Dynamic secrets","Terraform management","Unlimited config syncs","99.95% uptime SLO","Dedicated account manager"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Doppler is a secrets management platform that centralizes API keys, environment variables, and other credentials so engineering teams stop hardcoding secrets or scattering them across .env files and source control. Applications fetch secrets from Doppler at runtime, so a single rotation propagates everywhere the secret is used.$q$, $q$Founded in 2018 by Brian Vallelunga, Jack Legg, and Cesar D'Onofrio and headquartered in San Francisco, Doppler went through Y Combinator and has raised about $28.9 million from investors including Sequoia Capital and Google Ventures, serving over 31,500 customers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Secrets are organized into inheritable 'configs' scoped by project and environment, and can be accessed via the Doppler CLI, SDKs, REST API, or native integrations with Kubernetes, Vercel, AWS, GitHub Actions, and Terraform.$q$, $q$Team and Enterprise plans add change-request approval workflows, SAML SSO, role-based access control, automatic secret rotation, and detailed activity logging for auditability.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Doppler publishes transparent pricing: Developer is free for up to 3 users then $8/user/month, Team costs $21/user/month with a 14-day trial, and Enterprise is custom-priced with on-premise deployment, SCIM, dynamic secrets, and a 99.95% uptime SLO.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b899dd8e-5a92-4424-9a3d-1964775af19a', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$AI website generation$q$, $q$Generates a starting page layout, copy, and images from a text prompt to speed up building a new site.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$110+ templates and 250+ UI blocks$q$, $q$A large library of ready-made templates and drag-and-drop components for customizing pages without code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Built-in CMS$q$, $q$Manages blog posts and other dynamic, structured content directly within the site editor.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Custom domains$q$, $q$Connects one or more custom domains depending on plan, with free hosting included.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$White-label dashboard$q$, $q$Lets agencies manage and present client websites under their own branding rather than Dorik's.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Code export$q$, $q$Exports the underlying HTML/CSS for a built site, useful for handoff or self-hosting.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Unlimited storage and bandwidth$q$, $q$Hosting resources are not metered or capped, even on lower-priced plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Collaborator access$q$, $q$Business and Agency plans support multiple collaborators working on the same site.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Free plan is genuinely usable, including a custom domain and up to 200 blog posts.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Significantly cheaper than Webflow at comparable functionality levels.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$White-label dashboard and unlimited-site Agency plan make it attractive for agencies reselling websites.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Code export option avoids full platform lock-in for more advanced users.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Design flexibility is less granular than Webflow for users who want pixel-level control.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Smaller template and integration ecosystem compared to Wix or Squarespace.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Page and blog post limits on Free and Personal plans can be restrictive for content-heavy sites.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Smaller company and community than more established website builder competitors.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Is Dorik free to use?$q$, $q$Yes. Dorik offers a free plan that includes one custom domain, up to 25 pages, up to 200 blog posts, and unlimited storage and bandwidth, with Dorik branding included.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$How much does Dorik cost?$q$, $q$Paid plans on monthly billing start at $29/month for Personal, $59/month for Business, and $99/month for Agency, with lower effective costs on annual, 2-year, or one-time lifetime billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Who founded Dorik?$q$, $q$Dorik was founded in 2019 by Mizanur Rahman and Anwar Hossain and is based in Sylhet, Bangladesh.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Does Dorik require coding knowledge?$q$, $q$No. Dorik is a no-code website builder that uses templates, drag-and-drop blocks, and AI generation, though it also offers code export for users who want the underlying HTML/CSS.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Is Dorik good for agencies?$q$, $q$Yes. Dorik offers a white-label dashboard and an Agency plan with unlimited custom domains, pages, and collaborators, aimed specifically at agencies managing multiple client sites.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$How does Dorik compare to Webflow?$q$, $q$Dorik is generally simpler and less expensive than Webflow, trading some design granularity for faster setup, a genuinely usable free plan, and built-in AI generation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Small business websites$q$, $q$Launching a professional business or portfolio website quickly using templates and AI-generated starting content.$q$, $q$Solo entrepreneurs and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Agency client site management$q$, $q$Building and managing many client websites under an agency's own brand using the white-label dashboard.$q$, $q$Digital agencies and freelance web designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Blogging and content publishing$q$, $q$Running a blog or content-driven site using Dorik's built-in CMS without a separate blogging platform.$q$, $q$Content creators and small publishers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 custom domain","25 pages","200 blog posts","Unlimited storage and bandwidth"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Personal$q$, $q$$29/month$q$, $q$Monthly (from $10.38/month on 2-year billing)$q$, NULL, $q$["1 custom domain","25 pages","200 blog posts","AI website generation","Code export"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Business$q$, $q$$59/month$q$, $q$Monthly (from $20.75/month on 2-year billing)$q$, NULL, $q$["3 custom domains","Unlimited pages","10 collaborators","Unlimited blog posts","White-label dashboard"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$Agency$q$, $q$$99/month$q$, $q$Monthly (custom pricing available)$q$, NULL, $q$["Unlimited custom domains","Unlimited pages","Unlimited collaborators","Unlimited blog posts","White-label dashboard"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dorik is a no-code website builder that combines AI-assisted generation with more than 110 templates and 250 drag-and-drop UI blocks, letting users design, host, and publish a professional website entirely in the browser without writing code.$q$, $q$Founded in 2019 by Mizanur Rahman and Anwar Hossain and based in Sylhet, Bangladesh, Dorik launched publicly in 2020 and grew into a globally used SaaS product, notable for scaling significantly from outside a traditional startup hub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dorik includes a built-in CMS for blog posts and dynamic content, AI tools for generating copy, layouts, and images, custom domain support, and code export for users who want to extract the underlying HTML/CSS.$q$, $q$A white-label dashboard option lets agencies manage and resell client websites under their own brand, and hosting, storage, and bandwidth are included on every plan, including the free tier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dorik offers a genuinely usable Free plan (1 custom domain, 25 pages, 200 blog posts) alongside Personal ($29/month), Business ($59/month), and Agency ($99/month) paid tiers, with substantial discounts for annual, 2-year, or one-time lifetime billing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cf9cd65-f41d-4829-821a-01a2e4394707', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Multi-blog management$q$, $q$Runs multiple independent blogs from a single Dotclear installation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Wiki and XHTML syntax$q$, $q$Lets authors write entries using either a simplified wiki syntax or standard XHTML.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Native podcast support$q$, $q$Publishes and distributes audio content directly through the platform without a third-party plugin.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Standalone pages$q$, $q$Supports pages that exist independently from the chronological blog entry flow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Plugin and widget ecosystem$q$, $q$Extends core functionality through a community-maintained library of plugins and widgets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Theme customization$q$, $q$Changes site appearance using user-contributed themes distributed through DotAddict.org.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Multiple database support$q$, $q$Works with MySQL, MariaDB, PostgreSQL, or SQLite depending on the hosting environment.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Multilingual interface$q$, $q$Supports a multilingual admin interface and multilingual publishing capabilities.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Completely free and open source with no paid tiers or licensing fees.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Lightweight and focused specifically on blogging rather than general-purpose site building.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Long-running, continuously maintained project with over two decades of development history.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Strong, active community and plugin ecosystem, especially in French-speaking regions.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Much smaller plugin, theme, and community ecosystem than WordPress.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Adoption and available support resources are heavily concentrated in French-speaking countries.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Requires self-hosting and basic server administration knowledge, unlike hosted blogging services.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Smaller global market share means fewer third-party tutorials and integrations in English.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Is Dotclear free?$q$, $q$Yes. Dotclear is fully free and open-source software with no paid tiers. Users only pay for the web hosting they choose to run it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Who created Dotclear?$q$, $q$Dotclear was originally developed by French programmer Olivier Meunier starting in 2002 and released as open source in 2003.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$What license does Dotclear use?$q$, $q$Dotclear was originally released under GPLv2 and moved to the GNU Affero General Public License version 3 (AGPLv3) in March 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$How does Dotclear compare to WordPress?$q$, $q$Dotclear is smaller and more narrowly focused on blogging, with a lighter footprint and smaller plugin ecosystem than WordPress, which dominates the broader CMS and website-building market.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$What programming language is Dotclear written in?$q$, $q$Dotclear is written in PHP and supports MySQL, MariaDB, PostgreSQL, and SQLite databases.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Where is Dotclear most popular?$q$, $q$Dotclear's usage is heavily concentrated in France and other French-speaking regions, where it is used by several notable blogging platforms and institutions.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Personal and independent blogging$q$, $q$Running a self-hosted personal blog with full control over data and hosting, without relying on a proprietary platform.$q$, $q$Independent bloggers and writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Multi-blog publishing networks$q$, $q$Managing several distinct blogs from a single Dotclear installation and admin login.$q$, $q$Publishers and organizations running multiple blogs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Podcast publishing$q$, $q$Distributing audio content and episode feeds natively alongside written blog posts.$q$, $q$Independent podcasters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code and software","Multi-blog support","Plugin and theme ecosystem","Community support forums"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dotclear is a free, open-source content management system purpose-built for blogging, allowing a single self-hosted installation to run multiple independent blogs with support for wiki or XHTML syntax, standalone pages, and native podcast publishing.$q$, $q$Originally created by French developer Olivier Meunier in 2002 and released as open source in 2003, Dotclear is maintained entirely by a volunteer community rather than a company, with no headquarters or commercial ownership structure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Built in PHP with support for MySQL, MariaDB, PostgreSQL, and SQLite databases, Dotclear can be extended through community plugins and widgets and customized with user-contributed themes distributed via DotAddict.org.$q$, $q$The project moved from GPLv2 to the stronger AGPLv3 license in March 2024, and continues active development, including version 2.33's modernization of the admin interface toward vanilla JavaScript.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dotclear is entirely free and open source with no subscription tiers or paid version of the core software. The only cost is whatever web hosting a user chooses to run it on; some hosts offer one-click Dotclear installers as a convenience.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('280aa268-3174-4380-8d4f-ab00eb9ac2f7', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$IMAP and POP3 protocol support$q$, $q$Implements RFC-standard IMAP and POP3 for reliable, standards-compliant mailbox access across mail clients.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$LMTP local delivery$q$, $q$Supports the Local Mail Transfer Protocol for efficient handoff of mail from an MTA into user mailboxes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$ManageSieve and Sieve filtering$q$, $q$Lets users define and remotely manage server-side rules for sorting, forwarding, or discarding mail.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Self-optimizing indexes$q$, $q$Automatically maintains efficient mailbox indexes to keep large mailboxes fast to search and browse.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Self-healing data integrity$q$, $q$Includes mechanisms to detect and recover from mailbox data corruption without manual intervention.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Full-text search plugins$q$, $q$Supports Apache Solr integration or the newer built-in Xapian-based fts_flatcurve plugin for fast mailbox search.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Flexible authentication$q$, $q$Supports multiple authentication schemes including CRAM-MD5, DIGEST-MD5, and Lua-scripted authentication logic.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Dovecot Pro clustering$q$, $q$The commercial Pro Edition adds a cloud-native, stateless clustering architecture for high availability at carrier scale.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Free, mature, and extremely widely deployed open-source mail server with a strong security track record.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Publicly audited codebase, including a 2017 Mozilla-funded third-party security review.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Scales from a single free self-hosted server up to a fully supported commercial product without changing software.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Standards-compliant implementation with broad mail client compatibility.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Requires a separate mail transfer agent (such as Postfix) to form a complete email system, adding setup complexity.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Dovecot Pro pricing is not publicly listed and requires contacting Open-Xchange for a quote.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Community Edition is designed for single-server use, so scaling requires either manual clustering or upgrading to Pro.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Administration is command-line and configuration-file driven, with a learning curve for those unfamiliar with Unix mail systems.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Is Dovecot free?$q$, $q$Yes, the Dovecot Community Edition is free and open source. Open-Xchange also sells a commercially supported Pro Edition priced per mailbox for larger-scale deployments.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Who created Dovecot?$q$, $q$Dovecot was created by Finnish developer Timo Sirainen, who released the first version in July 2002.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$What is the difference between Dovecot and Postfix?$q$, $q$Dovecot handles IMAP/POP3 mailbox storage and retrieval for end users, while Postfix is a mail transfer agent that sends and routes mail between servers; the two are typically deployed together to form a complete email system.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$How much does Dovecot Pro cost?$q$, $q$Dovecot Pro pricing is not published publicly; Open-Xchange prices it based on the number of mailboxes under management, with lower per-mailbox costs at higher volumes, and requires a custom quote.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Has Dovecot been security audited?$q$, $q$Yes. In 2017, the Mozilla Open Source Support program funded the first public third-party security audit of the Dovecot codebase.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$What operating systems does Dovecot run on?$q$, $q$Dovecot runs on Unix-like operating systems, including Linux and BSD variants.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Self-hosted personal or small business email$q$, $q$Running a private IMAP/POP3 mail server on a single Linux server, paired with an MTA like Postfix.$q$, $q$Self-hosters and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Web hosting provider mail infrastructure$q$, $q$Bundling mailbox hosting for hosting-company customers on top of the free Community Edition.$q$, $q$Web hosting companies and ISPs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Carrier-scale enterprise email$q$, $q$Running Dovecot Pro's clustered, high-availability architecture to serve millions of mailboxes for large enterprises or telecoms.$q$, $q$Large enterprises and telecom providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source IMAP and POP3 server","Single-server deployment","Sieve mail filtering","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$Dovecot Pro$q$, $q$Custom (priced per mailbox)$q$, $q$Annual contract$q$, NULL, $q$["Cloud-native clustering architecture","High availability at scale","Dedicated vendor support","Volume-based mailbox pricing"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dovecot is a security-focused, open-source mail server implementing the IMAP and POP3 protocols for Unix-like systems. It handles mailbox storage and retrieval, and is typically paired with a separate mail transfer agent like Postfix for sending and routing mail.$q$, $q$Originated by Finnish developer Timo Sirainen with a first release in July 2002, Dovecot grew into one of the most widely deployed open-source IMAP servers in the world, with its commercial direction now stewarded by Open-Xchange through the Dovecot Pro product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dovecot implements IMAP, POP3, LMTP for local delivery, and ManageSieve for remote mail-filtering rule management, with support for authentication mechanisms like CRAM-MD5 and DIGEST-MD5.$q$, $q$Full-text search is available through Solr integration or the newer built-in fts_flatcurve plugin (Dovecot 2.4+), and the platform is known for self-optimizing indexes and self-healing recovery from data corruption.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition is completely free and open source, designed for single-server deployments. Dovecot Pro, sold by Open-Xchange for larger-scale and enterprise deployments, is priced per mailbox with volume-based discounts and is custom-quoted rather than listed publicly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('da8a9e8f-5d1d-43cb-8de7-2ebf5cb6c5b8', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Lightweight Go SMTP server$q$, $q$A small, dependency-light SMTP implementation that uses only a few megabytes of RAM.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Standard port support$q$, $q$Listens on ports 25, 465, and 587 to handle both traditional and modern TLS-encrypted mail submission.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Per-user DKIM signing$q$, $q$Signs outbound mail per user to improve deliverability and reduce the chance of messages being marked as spam.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Hook-based message handling$q$, $q$Pipes received and sent messages to user-defined scripts in mbox format for fully customizable storage or routing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Multi-domain support$q$, $q$Can handle email for multiple domains from a single running instance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Single JSON configuration file$q$, $q$All server settings are defined in one minimal configuration file rather than a complex admin panel.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Optional web interface$q$, $q$Provides a basic browsable view of received emails without requiring a separate mail client.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$TLS encryption$q$, $q$Supports encrypted connections for secure mail transmission.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Completely free and open source with no company, subscription, or license fees involved.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Extremely lightweight, using only a few megabytes of RAM to run.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Minimal, single-file configuration makes setup fast for technically comfortable users.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Hook-based architecture gives full flexibility over how mail is stored or processed.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$No built-in IMAP support, so it cannot replace a full mailbox server on its own.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Small, individually maintained project with limited documentation and no commercial support.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$No graphical admin panel; setup and mail handling require writing shell scripts and editing JSON config.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Very limited public adoption data, making long-term maintenance and community support harder to gauge.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Is Dovel free?$q$, $q$Yes. Dovel is fully free and open source under the LGPL-3.0 license, with no paid tiers or company behind it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$What is Dovel used for?$q$, $q$Dovel is a lightweight, self-hosted SMTP server that lets developers send and receive email for one or more domains with minimal configuration, typically for personal or small-scale technical use cases.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Does Dovel support IMAP?$q$, $q$No. Dovel focuses specifically on SMTP for sending and receiving mail; it does not include built-in IMAP support for full mailbox management.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$What programming language is Dovel written in?$q$, $q$Dovel is written in the Go programming language and distributed as a Go module.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Who maintains Dovel?$q$, $q$Dovel is an independent, community-maintained open-source project rather than a product backed by a company; it was first shared publicly via a Show HN post on Hacker News in 2023.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$How does Dovel handle received emails?$q$, $q$Dovel uses a hook system that pipes each received or sent message, in mbox format, to a user-defined script, giving operators full control over how mail is stored or processed.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Personal self-hosted email$q$, $q$Running a minimal, self-controlled SMTP server for personal domains without relying on a third-party email provider.$q$, $q$Individual developers and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Custom mail-processing pipelines$q$, $q$Wiring incoming or outgoing mail into custom scripts and automation via the hook system for specialized workflows.$q$, $q$Developers building custom infrastructure$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Email security research and testing$q$, $q$Standing up a lightweight, auditable SMTP server for testing DKIM, TLS, and mail delivery behavior.$q$, $q$Security researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code","Multi-domain SMTP support","DKIM signing","Optional web interface"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dovel is a free, open-source SMTP server written in Go, built to let developers self-host basic email sending and receiving with minimal configuration. It was introduced via a Show HN post on Hacker News in early 2023 as a way to self-host email in three steps.$q$, $q$Dovel is not backed by a company; it is an independently maintained open-source project distributed through public git repositories at dovel.email under the LGPL-3.0 license, with no headquarters, funding, or commercial ownership structure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dovel listens on standard SMTP ports (25, 465, 587), supports TLS encryption, per-user DKIM signing, and can serve multiple domains from a single instance, all configured through one JSON file.$q$, $q$Incoming and outgoing mail is processed through a hook system, executing user-defined scripts that receive each message in mbox format, giving operators full flexibility over storage and routing rather than a fixed mailbox format.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dovel is entirely free and open source under the LGPL-3.0 license, with no paid tiers. The only costs are the server it runs on and standard domain/DNS setup required for email deliverability.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d1caaa4a-2950-4499-9b5a-375119656c09', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
